namespace Cpp.Api;
public interface IFulfillmentGateway { Task<SubmissionResult> SubmitOrderAsync(Order order, CancellationToken ct); Task<string> GetSubmissionStatusAsync(string webOrderNumber, CancellationToken ct); }
public class MockJdeFulfillmentGateway(IConfiguration config) : IFulfillmentGateway {
 public async Task<SubmissionResult> SubmitOrderAsync(Order o,CancellationToken ct){ await Task.Delay(350,ct); if(config.GetValue<bool>("MockJde:FailSubmissions")) throw new InvalidOperationException("The demonstration JDE adapter rejected this submission."); var web=$"WEB-{DateTime.UtcNow:yyyy}-{Random.Shared.Next(100000,999999)}"; var split=o.Lines.Any(x=>x.Uom=="GA"&&x.Quantity>6098); return new(web, split?[web+"-01",web+"-02"]:[web+"-01"],split?"Quantity above 6098 GA requires transportation split.":null); }
 public Task<string> GetSubmissionStatusAsync(string id,CancellationToken ct)=>Task.FromResult("Submitted");
}
public interface IOrderRuleService { List<ValidationResult> Validate(OrderRequest order, Account? account, IReadOnlyDictionary<string,Product> products); }
public class OrderRuleService : IOrderRuleService { public List<ValidationResult> Validate(OrderRequest o,Account? a,IReadOnlyDictionary<string,Product> products){ var r=new List<ValidationResult>(); if(a is null)r.Add(new("error","ACCOUNT_ACCESS","Select an authorized Ship-To account.","shipToAccountId")); if(!new[]{"Standard","Customer Pickup","Expedited","Contract Freight"}.Contains(o.FreightOption))r.Add(new("error","FREIGHT","Select a valid freight option.","freightOption")); if(!o.ContactEmail.Contains('@'))r.Add(new("error","EMAIL","Enter a valid contact email.","contactEmail")); if(o.RequestedArrivalDate.Date<DateTime.UtcNow.Date)r.Add(new("error","ARRIVAL_DATE","Requested arrival date cannot be in the past.","requestedArrivalDate")); if(a?.RequiresCustomerPo==true&&string.IsNullOrWhiteSpace(o.CustomerPo))r.Add(new("error","PO_REQUIRED","This account requires a customer PO number.","customerPo")); if(o.Lines.Count==0)r.Add(new("error","LINES_REQUIRED","Add at least one product.","lines")); foreach(var l in o.Lines){ if(!products.TryGetValue(l.ProductId,out var p)){r.Add(new("error","PRODUCT_UNKNOWN","A selected product is no longer available.","lines"));continue;} if(!p.Orderable)r.Add(new("error","NOT_ORDERABLE",$"{p.Name} has no availability.","lines","Choose an available SKU.")); if(l.Quantity<p.MinimumQuantity||l.Quantity>p.MaximumQuantity||l.Quantity%p.QuantityIncrement!=0)r.Add(new("error","QUANTITY",$"Quantity for {p.Name} must be {p.MinimumQuantity}–{p.MaximumQuantity} in increments of {p.QuantityIncrement}.","lines")); if(l.Uom=="GA"&&l.Quantity>6098)r.Add(new("warning","TRANSPORT_SPLIT","Quantities above 6098 GA will split into multiple sub-orders to facilitate transportation.","lines","Acknowledge the planned split.")); } return r; } }
